import { Component, OnInit } from '@angular/core';
import { Router, NavigationEnd } from '@angular/router';
import { AuthService } from './services/auth.service';
import { CartService } from './services/cart.service';
import { filter } from 'rxjs/operators';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  title = 'ShopEasy';
  isLoggedIn = false;
  userName = '';
  isAdmin = false;
  cartCount = 0;
  showDropdown = false;

  constructor(
    private authService: AuthService,
    private cartService: CartService,
    private router: Router
  ) {}

  ngOnInit() {
    console.log('🚀 AppComponent initialized');
    
    // Check authentication status on app load
    this.checkAuthStatus();

    // Subscribe to auth changes
    this.authService.currentUser.subscribe(user => {
      console.log('👤 Auth state changed:', user ? 'logged in' : 'logged out');
      this.isLoggedIn = !!user;
      this.userName = user?.name || '';
      this.isAdmin = user?.isAdmin || false;
      
      // Refresh cart when user logs in
      if (this.isLoggedIn) {
        console.log('🔄 User logged in, refreshing cart');
        this.cartService.refreshCart();
        
        // If user is on login page after login, redirect to home
        if (this.router.url === '/login' || this.router.url === '/register') {
          this.router.navigate(['/home']);
        }
      } else {
        console.log('👤 User logged out, clearing cart count');
        this.cartCount = 0;
      }
    });

    // Subscribe to cart count changes
    this.cartService.cartCount$.subscribe(count => {
      console.log('🛒 Cart count updated:', count);
      this.cartCount = count;
    });

    // Check authentication on every route change
    this.router.events.pipe(
      filter(event => event instanceof NavigationEnd)
    ).subscribe((event: any) => {
      console.log('🔄 Route changed to:', event.url);
    });
  }

  /**
   * Check if user is authenticated
   */
  checkAuthStatus(): void {
    const isLoggedIn = this.authService.isLoggedIn();
    const currentUrl = this.router.url;
    
    console.log('🔒 Auth check:', { isLoggedIn, currentUrl });
    
    // If not logged in and trying to access any page other than login/register/forgot-password, redirect to login
    if (!isLoggedIn && 
        currentUrl !== '/login' && 
        currentUrl !== '/register' && 
        currentUrl !== '/forgot-password' && 
        currentUrl !== '/') {
      console.log('🔒 Not authenticated, redirecting to login from:', currentUrl);
      this.router.navigate(['/login']);
    }
  }

  /**
   * Toggle dropdown menu
   */
  toggleDropdown(): void {
    this.showDropdown = !this.showDropdown;
    console.log('📱 Dropdown toggled:', this.showDropdown);
  }

  /**
   * Close dropdown menu
   */
  closeDropdown(): void {
    this.showDropdown = false;
  }

  /**
   * Logout user
   */
  logout(): void {
    console.log('👋 Logging out user');
    this.authService.logout();
    this.showDropdown = false;
    this.router.navigate(['/login']);
  }

  /**
   * Handle search
   */
  onSearch(query: string): void {
    if (query && query.trim()) {
      console.log('🔍 Searching for:', query);
      this.router.navigate(['/home'], { queryParams: { search: query.trim() } });
    }
  }

  /**
   * Get user initials for avatar
   */
  getUserInitials(): string {
    if (!this.userName) return '';
    return this.userName.split(' ').map(n => n[0]).join('').toUpperCase();
  }
}
